mapper.update:
UPDATE material
status = #{status}, title = #{title}, description = #{description}, raw_content = #{rawContent}, source_url = #{sourceUrl}, comment = #{comment}, score = #{score}, invalid_reason = #{invalidReason}, inbox_at = #{inboxAt}, inbox_read_at = #{inboxReadAt}, inbox_read_at = NULL, collected_at = #{collectedAt}, collected_read_at = #{collectedReadAt}, collected_read_at = NULL, archived_at = #{archivedAt}, invalid_at = #{invalidAt}, is_deleted = #{isDeleted}, deleted_at = #{deletedAt}, updated_at = #{updatedAt}
WHERE id = #{id}

UPDATE material
SET invalid_reason = NULL,
    invalid_at = NULL,
    updated_at = #{updatedAt}
WHERE id = #{id}

UPDATE material
SET archived_at = NULL,
    updated_at = #{updatedAt}
WHERE id = #{id}

mapper.sql:
FROM material m
WHERE m.user_id = #{userId}
  AND m.is_deleted = 0

    AND m.topic_id = #{topicId}


    AND m.status IN

        #{status}



    AND m.material_type IN

        #{materialType}



    AND m.score  >=  #{scoreMin}


    AND m.score  <=  #{scoreMax}


    AND m.created_at  >=  #{createdStart}


    AND m.created_at  <=  #{createdEnd}


    AND (
        m.title LIKE CONCAT('%', #{keyword}, '%')
        OR m.raw_content LIKE CONCAT('%', #{keyword}, '%')

            OR m.comment LIKE CONCAT('%', #{keyword}, '%')

    )



        AND EXISTS (
            SELECT 1
            FROM material_tag mt
            WHERE mt.material_id = m.id
              AND mt.tag_group_key = #{filter.tagGroupKey}

                AND mt.tag_value IN

                    #{tagValue}


        )



    AND (
        (m.status = 'INBOX' AND m.inbox_read_at IS NULL)
        OR (m.status = 'COLLECTED' AND m.collected_read_at IS NULL)
    )

mapper.select:
SELECT m.status AS name, COUNT(1) AS count
FROM material m
WHERE m.user_id = #{userId}
  AND m.is_deleted = 0

    AND m.topic_id = #{topicId}

GROUP BY m.status

